SELECT COUNT(*) AS total_standard_formats
FROM video_resource_formats
WHERE is_standard = 1;

SELECT format_name
FROM video_resource_formats
WHERE is_standard = 1;

SELECT user_id, COUNT(format_id) AS custom_format_count
FROM custom_formats
GROUP BY user_id;

SELECT AVG(format_count) AS average_formats_created
FROM (
    SELECT created_by, COUNT(format_id) AS format_count
    FROM video_resource_formats
    GROUP BY created_by
) AS user_format_counts;

SELECT COUNT(*) 
FROM custom_mappings 
WHERE user_id = 1;

SELECT COUNT(DISTINCT user_id) 
FROM format_search_history 
WHERE search_date = '2023-05-01';

SELECT description
FROM video_resource_formats
WHERE format_id = 1;
